using Microsoft.AspNetCore.Mvc; using SchoolEnterprise.Helpers; using SchoolEnterprise.Models.Domain; using SchoolEnterprise.Repositories; using SchoolEnterprise.Services;
namespace SchoolEnterprise.Controllers; [RoleGuard("Admin","Teacher")] public class AttendanceController(AttendanceRepository repo, SequenceService seq):Controller{ public IActionResult Board()=>View(); [HttpPost] public IActionResult Save(int recordId,bool isPresent){repo.Upsert(new AttendanceEntry{AttendanceId=seq.Next("AttendanceId"),StudentRecordId=recordId,Date=DateTime.Today,IsPresent=isPresent}); return RedirectToAction(nameof(Board));}}
